{
  "audit_scope": {
    "task_id": "L1-001",
    "type": "policy_qa",
    "question": "现行制度下,单笔费用报销达到多少金额需要部门总经理审批?",
    "period": "现行(2025年起)",
    "organization": "XX证券"
  },
  "verified_facts": [
    "《XX证券费用报销管理办法(2025修订版)》第五条:单笔费用报销的审批权限,不在本办法正文列示具体金额,统一按《XX证券授权管理办法》附件二执行。",
    "《XX证券授权管理办法》附件二AR-03:单笔报销金额大于等于10,000元且小于50,000元,审批角色为部门总经理。",
    "《XX证券费用报销管理办法(2022版)》已于2025年1月1日废止,其规定的8,000元部门总经理审批线不再适用。"
  ],
  "applicable_policies": [
    {"doc_id": "01_expense_reimbursement_2025.md", "clause_no": "第五条", "role": "审批权限委派"},
    {"doc_id": "03_authorization_management.md", "clause_no": "第二条 附件二 AR-03", "role": "具体审批金额阈值"}
  ],
  "findings": [],
  "impact": "无",
  "recommendations": "无",
  "anomaly_ids": [],
  "record_ids": [],
  "citations": [
    {"doc_id": "01_expense_reimbursement_2025.md", "clause_no": "第五条"},
    {"doc_id": "03_authorization_management.md", "clause_no": "第二条 附件二 AR-03"}
  ],
  "answer": "无异常。现行制度下,单笔费用报销金额达到10,000元(含)以上需要部门总经理审批。依据《XX证券费用报销管理办法(2025修订版)》第五条,审批金额统一按《XX证券授权管理办法》附件二执行;附件二AR-03规定:单笔报销金额大于等于10,000元且小于50,000元的,审批角色为部门总经理。",
  "limitations": []
}

